import { useState } from "react";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️"];

const toppingPrices = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
};

const BASE_PRICE = 299;

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function handleSelectTopping(topping) {
    setSelected(topping);
  }

  function handlePizzaClick(event) {
    const rect = event.currentTarget.getBoundingClientRect();

    const topping = {
      emoji: selected,
      x: event.clientX - rect.left,
      y: event.clientY - rect.top,
    };

    setPizza([...pizza, topping]);
  }

  function calculateTotal() {
    let total = BASE_PRICE;
    for (const topping of pizza) {
      total += toppingPrices[topping.emoji] || 0;
    }
    return total;
  }

  return (
    <div style={{ display: "flex", gap: "2rem", padding: "2rem", alignItems: "flex-start" }}>
      <div>
        <h1>🍕 Pizza Builder</h1>

        <h2 style={{ marginBottom: "1rem" }}>
          <strong>Total:</strong> ₹{calculateTotal()}
        </h2>

        <p style={{ display: "flex", gap: "0.5rem", flexWrap: "wrap", marginBottom: "1.5rem" }}>
          {toppings.map((topping) => (
            <button
              key={topping}
              onClick={() => handleSelectTopping(topping)}
              disabled={selected === topping}
              style={{
                padding: "0.5rem 1rem",
                fontSize: "1.5rem",
                cursor: selected === topping ? "default" : "pointer",
                opacity: selected === topping ? 0.6 : 1,
              }}
            >
              {topping}
            </button>
          ))}
        </p>

        <p style={{ fontSize: "0.9rem", color: "var(--text-secondary)" }}>
          Click on the pizza to add selected topping
        </p>
      </div>

      <figure
        onClick={handlePizzaClick}
        style={{
          position: "relative",
          width: "350px",
          margin: 0,
          cursor: "crosshair",
        }}
      >
        <img
          src="https://www.shutterstock.com/image-illustration/pizza-no-topping-260nw-2685328587.jpg"
          width="350"
          alt="Pizza"
        />

        {pizza.map((topping, index) => (
          <span
            key={index}
            style={{
              position: "absolute",
              left: topping.x,
              top: topping.y,
              fontSize: "2rem",
              pointerEvents: "none",
              transform: "translate(-50%, -50%)",
            }}
          >
            {topping.emoji}
          </span>
        ))}
      </figure>
    </div>
  );
}
